        OKAY_I_LL_HELP_YOU_OUT_SHUT_YOUR                                          = 7185,  -- Okay, I'll help you out. Shut your eyes...
        WHY_DON_T_YOU_LIKE_MAKE_YOU_RE                                            = 7186,  -- Why don't you, like, make %? You're gonna need these, though...
