        SUCH_INGENUITY_SUCH_INVENTIVENESS_I_COMMEND_YOU_ON                        = 7206,  -- Such ingenuity, such inventiveness! I commend you on your efforts and hereby grant you the title of craftsman. Continue to polish your skills and your bracelets and bijoux will shine even brighter!
        IS_A_WONDERFUL_NEW_METHOD_OF_GOLDSMITHING_THAT                            = 7207,  -- % is a wonderful new method of goldsmithing that allows you to enchant precious metals with the mysterious energy of black magic and anima.
        IS_A_WONDERFUL_NEW_METHOD_OF_GOLDSMITHING_THAT_2                          = 7208,  -- % is a wonderful new method of goldsmithing that allows you to enchant precious metals with the mysterious energy of white magic and anima.
        I_SEE_YOU_HAVE_BECOME_A_REGISTERED_CRAFTSMAN                              = 7209,  -- I see you have become a registered craftsman in another guild--and this after I warned you that your goldsmithing skills would go down if you did.
        YOU_ARE_AN_ELITE_GOLDSMITH_I_KNOW_FEW                                     = 7210,  -- %, you are an elite goldsmith. I know few who can match your talent. And that is why I want you to concentrate on your work for this guild.
        WILL_YOU_CONSIDER_REVOKING_YOUR_CRAFTSMAN_STATUS_IN                       = 7211,  -- Will you consider revoking your craftsman status in all other guilds? If you like, I can contact the other guildmasters and tell them of your decision.
