        HMM_THE_SYNTHESIS_ITEMS_FOR_THAT_RANK_ARE                                 = 7215,  -- Hmm, the synthesis items for that rank are still beyond your skill, I'm afraid.
        IS_A_WONDERFUL_NEW_METHOD_OF_GOLDSMITHING_THAT_3                          = 7216,  -- % is a wonderful new method of goldsmithing that allows you to shape softened ingots with a mandrel, making it easier to process more chains with one crystal.
