        IS_A_WONDERFUL_NEW_METHOD_OF_GOLDSMITHING_THAT_5                          = 7218,  -- % is a wonderful new method of goldsmithing that allows you to craft mechanical parts based on the same techniques used to build timepieces.
        LET_S_SEE_NOW_THIS_SHAFT_S_CONNECTED                                      = 7219,  -- Let's see now... This shaft's connected to...this gear. This gear's connected to my...belt buckle? Could you, like, not talk to me right now?
