        BUT_BE_WARNED_THIS_MAGIC_HAS_THE_SIDE                                     = 7353,  -- But be warned--this magic has the side effect of preventing you from attacking any other monster for three whole Vana'dielian days, kupo!
        THIS_NEW_WEAPON_THE_WAS_DEVELOPED_AS_A                                    = 7354,  -- This new weapon, the %, was developed as a countermeasure for serious situations such as this, kupo. It has been designed with the ability to absorb malicious auras emitted by enemies.
