        GOOD_JOB_KUPO_YOU_SURE_SHOWED_THEM_WHO                                    = 7360,  -- Good job, kupo! You sure showed them who's boss! Thanks to you, we were able to avoid a diplomatic disaster with the Far East, kupo.
        A_HANDFUL_OF_NO_GOOD_NOMAD_MOOGLES_AND                                    = 7361,  -- A handful of no-good nomad moogles and Goblins were conspiring to take over the MHMU, wilfully assuming false identities in order to obtain the armor and frame us, kupo!
