        YOU_HAVE_EQUIPPED_GREAT_NOW_HOLD_STILL_WHILE                              = 7365,  -- You have % equipped! Great! Now, hold still while I cast miraculously marvelous moogle magic on it, kupo.
        AFTER_YOU_VE_TAKEN_CARE_OF_THE_ARMOR                                      = 7366,  -- After you've taken care of the armor wearer, plant your % into the ground near the fallen fiend. You'll get a reward that matches the amount of malice absorbed, kupo.
        THE_MALICE_ABSORPTION_MAGIC_WILL_LOSE_EFFECT_IF                           = 7367,  -- The malice absorption magic will lose effect if you move to another area, so come back here if you want me to cast it again, kupo.
        YOU_HAVE_EQUIPPED_I_LIKE_YOUR_ENTHUSIASM_NOW                              = 7368,  -- You have % equipped! I like your enthusiasm! Now, hold still while I cast miraculously marvelous moogle magic on it, kupo.
        AFTER_YOU_VE_SEEN_TO_THE_WRETCHED_ROGUE                                   = 7369,  -- After you've seen to the wretched rogue inside the armor, plant your % into the ground near the fallen fiend. You'll get a reward that matches the amount of malice absorbed, kupo.
        WE_NEED_YOUR_HELP_TO_CLEAR_THE_LAND_2                                     = 7370,  -- We need your help to clear the land of the malice-emitting menace, but you need to equip the % you have in your possession, kupo!
        NOOO_THAT_WON_T_DO_COME_BACK_AGAIN                                        = 7371,  -- Nooo, that % won't do. Come back again after you have % equipped, kupo!
        KUPOPO_THERE_S_NO_MALICE_HERE_AT_ALL                                      = 7372,  -- Kupopo! There's no malice here at all. Please absorb lots more and try again, kupo.
        KUPOPO_YOU_VE_ABSORBED_MALICE_KUPO_HERE_S                                 = 7373,  -- Kupopo! You've absorbed [a bit of/some/lots of] malice, kupo. Here's your reward!
        THANKS_KUPO_WE_WANT_YOU_TO_ABSORB_EVEN                                    = 7374,  -- Thanks, kupo. We want you to absorb even more malice, and weaken those armored evildoers, kupo!
