        WHICH_AREA_DO_YOU_WANT_TO_KNOW_ABOUT                                      = 7554,  -- Which area do you want to know about?
        WHICH_AREA_DO_YOU_WANT_TO_KNOW_ABOUT_2                                    = 7555,  -- Which area do you want to know about? The Mog House, Metalworks, and the port. The shops and the Mines District. The Kulatz Bridge and the West Gate.
