        FROM_HERE_YOU_CAN_SEE_ON_THE_LEFT                                         = 7564,  -- From here you can see on the left, in order, the Goldsmiths' Guild and the jewelry store. Further back along the canal is a housing area.
        ON_THE_RIGHT_IS_THE_AREA_WHERE_STREET                                     = 7565,  -- On the right is the area where street vendors set up shop, and further down you'll find more houses and the music store.
