        THE_MINES_DISTRICT_IS_WHERE_YOU_LL_FIND                                   = 7567,  -- The Mines District is where you'll find the Zeruhn Mines, the Alchemists' Guild, and the South Gate.
        ON_THE_OTHER_SIDE_OF_THIS_FOUNTAIN_IS                                     = 7568,  -- On the other side of this fountain is the auction house. You can bid for items or put your own items up for sale at the auctioneer's window.
