        YOU_SHOULD_BE_ABLE_TO_FIND_ONE_OF                                         = 7572,  -- You should be able to find one of the guards in charge of assigning missions, and a high guard in charge of conquests, nearby.
        COME_BACK_AND_ASK_ME_AGAIN_IF_YOU                                         = 7573,  -- Come back and ask me again if you need further assistance.
        YOU_ARE_AT_BASTOK_S_WEST_GATE_GO                                          = 7574,  -- You are at Bastok's West Gate. Go through the gate if you want to go to South Gustaberg.
        THE_ENTRANCE_TO_THE_METALWORKS_BASTOK_S_ADMINISTRATIVE                    = 7575,  -- The entrance to the Metalworks, Bastok's administrative and manufacturing center, is just a few steps to the north.
        IF_YOU_GO_FURTHER_NORTH_YOU_LL_BE                                         = 7576,  -- If you go further north, you'll be on the road leading to Port Bastok.
        OVER_THERE_TO_THE_EAST_IS_THE_ENTRANCE                                    = 7577,  -- Over there to the east is the entrance to the residential area where your Mog House is located.
