        ALL_THREE_NATIONS_ARE_STRIVING_DAILY_TO_PUT                               = 7831,  -- All three nations are striving daily to put more regions under their control. This is what we call conquests. You can take part in it and serve your country by defeating enemies while you have Signet cast on you.
        EACH_REGION_COMPRISES_SEVERAL_AREAS_AND_THE_NATION                        = 7832,  -- Each region comprises several areas, and the nation that rids those areas of the most monsters gains control of the region.
        NATIONS_RECEIVE_GOODS_AND_RESOURCES_FROM_REGIONS_UNDER                    = 7833,  -- Nations receive goods and resources from regions under their control.
        SO_THE_MORE_REGIONS_WE_CONTROL_THE_RICHER                                 = 7834,  -- So, the more regions we control, the richer our nation becomes.
        BORDER_GUARDS_ARE_ALSO_PLACED_IN_OUTPOSTS_WITHIN                          = 7835,  -- Border guards are also placed in outposts within regions under our control. They are there to cast Signet on adventurers like yourself.
        ONCE_YOU_HAVE_YOUR_NATION_S_SIGNET_YOU                                    = 7836,  -- Once you have your nation's Signet, you will be able to acquire crystals from enemies you defeat.
        NOT_ONLY_THAT_BUT_YOU_WILL_ALSO_RECEIVE                                   = 7837,  -- Not only that, but you will also receive conquest points. You get more conquest points if you defeat enemies in regions that are not under your nation's control. These points can be used to purchase items from guards like myself.
        SO_YOU_SEE_CONQUESTS_BENEFIT_NATIONS_AND_ADVENTURERS                      = 7838,  -- So you see...conquests benefit nations and adventurers alike. We expect you to do your best to serve your country.
        YOU_CAN_SEE_THE_CURRENT_STATE_OF_CONQUESTS                                = 7839,  -- You can see the current state of conquests by selecting Region Info from the main menu. Conquest results in all regions are regularly recalculated, so you may want to check them from time to time.
        SHOPS_IN_OUR_CITY_WILL_BE_SELLING_DIFFERENT                               = 7840,  -- Shops in our city will be selling different items according to our conquest rank. The Troupe Valeriano will also visit the nation that finishes first and bring a little joy to its citizens.
        YOU_CAN_DONATE_CRYSTALS_TO_YOUR_NATION_ONCE                               = 7841,  -- You can donate crystals to your nation once you achieve rank 2. Just trade them to guards like myself, and we will ensure they are sent to the proper place.
        WE_WOULD_LIKE_YOU_TO_DONATE_CRYSTALS_TO                                   = 7842,  -- We would like you to donate crystals to your nation from now on. Just trade them to guards like myself, and we will ensure they are sent to the proper place.
        YOU_CAN_ACQUIRE_CRYSTALS_BY_DEFEATING_ENEMIES_WHILE                       = 7843,  -- You can acquire crystals by defeating enemies while you have your nation's Signet. Having Signet cast on you is also the only way of taking part in conquests.
        RANK_POINTS_WILL_BE_AWARDED_TO_YOU_FOR                                    = 7844,  -- Rank points will be awarded to you for each crystal you donate, and you may be offered new missions as your rank goes up.
        YOU_ALSO_RECEIVE_RANK_POINTS_FOR_COMPLETING_MISSIONS                      = 7845,  -- You also receive rank points for completing missions. Complete missions and take part in conquests to raise your rank and serve your country.
        YOU_ARE_AWARDED_CONQUEST_POINTS_WHEN_YOU_DEFEAT                           = 7846,  -- You are awarded conquest points when you defeat monsters while you are taking part in conquests. Select "Region Info" from the menu to check your current number of conquest points.
        YOU_CAN_PURCHASE_ITEMS_FROM_GUARDS_LIKE_MYSELF                            = 7847,  -- You can purchase items from guards like myself with your conquest points, but be warned that the number of points you spend will be subtracted from your current total.
        WHEN_CONQUEST_RESULTS_ARE_ANNOUNCED_YOU_WILL_BE                           = 7848,  -- When conquest results are announced, you will be told which country controls the region you are in at that time. Sometimes regions may become neutral, or beastmen may even gain control of regions.
        IF_WE_GAIN_CONTROL_OF_A_REGION_BORDER                                     = 7849,  -- If we gain control of a region, border guards will be placed at its outposts to help adventurers like you.
        MERCHANTS_WILL_ALSO_BE_PLACED_THERE_AND_GOODS                             = 7850,  -- Merchants will also be placed there, and goods from that region will find their way to the local shops here.
        GAINING_CONTROL_OF_REGIONS_IS_THE_BASIC_PRINCIPLE                         = 7851,  -- Gaining control of regions is the basic principle behind conquests. We need each of you to do your best, and bring our nation to the top of the ranks.
        OF_COURSE_SOMETIMES_WE_LOSE_REGIONS_TO_OTHER                              = 7852,  -- Of course, sometimes we lose regions to other nations...so we must try to take them back before the next conquest results are announced.
        AS_AN_INCENTIVE_WE_WILL_AWARD_YOU_WITH                                    = 7853,  -- As an incentive, we will award you with more conquest points for defeating monsters in those regions.
        BUT_IF_WE_ARE_ALLIED_WITH_ANOTHER_NATION                                  = 7854,  -- But if we are allied with another nation, you will only be awarded the regular rate for defeating monsters in our allies' regions. On the other hand, we will award you with more points for fighting in the top-ranked nation's regions.
        OUR_PARAMOUNT_CONCERN_LIES_IN_THE_BEASTMEN_GAINING                        = 7855,  -- Our paramount concern lies in the beastmen gaining control of our regions. If too many of us are defeated in a region, the beastmen will gain control of it.
        IF_THIS_HAPPENS_NOT_ONLY_IS_IT_A                                          = 7856,  -- If this happens, not only is it a great blow to our pride, but you will be unable to acquire any crystals in that region.
        THE_BEASTMEN_ARE_A_MENACE_TO_ALL_NATIONS                                  = 7857,  -- The beastmen are a menace to all nations. If they rise to power, we must all unite and drive those vile creatures from that region.
        WE_NEED_YOU_TO_BRING_SUPPLIES_TO_THE                                      = 7858,  -- We need you to bring supplies to the outpost border guards who are placed in regions under our control.
        THERE_IS_ONE_OUTPOST_IN_EACH_REGION_SELECT                                = 7859,  -- There is one outpost in each region. Select Region Info from the menu, and look for the areas with a small flag mark on the map. That is where they are.
        HERE_ARE_THE_SUPPLIES_JUST_GIVE_THEM_TO                                   = 7860,  -- Here are the supplies. Just give them to the guard at the outpost and your mission will be complete. Now, choose which outpost you want to go to. We give different rewards for each region, so choose carefully.
        WHERE_DO_YOU_WISH_TO_TAKE_THE_SUPPLIES                                    = 7861,  -- Where do you wish to take the supplies? @ @ @ @ @ The Ronfaure Region.[/ (Done)] The Zulkheim Region.[/ (Done)] The Norvallen Region.[/ (Done)] The Gustaberg Region.[/ (Done)] The Derfland Region.[/ (Done)] The Sarutabaruta Region.[/ (Done)] The Kolshushu Region.[/ (Done)] The Aragoneu Region.[/ (Done)] The Fauregandi Region.[/ (Done)] The Valdeaunia Region.[/ (Done)] Qufim Island.[/ (Done)] The Li'Telor Region.[/ (Done)] The Kuzotz Region.[/ (Done)] The Vollbow Region.[/ (Done)] The Elshimo Lowlands Region.[/ (Done)] The Elshimo Uplands Region.[/ (Done)] Tu'Lia.[/ (Done)] @ The Tavnazian Archipelago.[/ (Done)] @ @ @ @ @ @ @ Cancel.
        WHICH_E_F_WOULD_YOU_LIKE_TO_JOIN                                          = 7862,  -- Which E.F. would you like to join? . . . . . . The Zulkheim Region (Lv.20`). The Norvallen Region (Lv.25`). . The Derfland Region (Lv.25`). . The Kolshushu Region (Lv.20`). The Aragoneu Region (Lv.25`). The Fauregandi Region (Lv.35`). The Valdeaunia Region (Lv.40`). The Qufim Region (Lv.25`). The Li'Telor Region (Lv.35`). The Kuzotz Region (Lv.40`). The Vollbow Region (Lv.65`). The Elshimo Lowlands Region (Lv.35`). The Elshimo Uplands Region (Lv.45`). . . . . . . . . . . None.
        SO_BE_IT_YOU_HAVE_UNTIL_THE_NEXT                                          = 7863,  -- So be it. You have until the next conquest results announcement to complete this mission. Good luck.
        WE_WILL_DISPOSE_OF_THOSE_UNUSABLE_SUPPLIES                                = 7864,  -- We will dispose of those unusable supplies.
        YOU_CAN_ONLY_UNDERTAKE_ONE_SUPPLY_MISSION_PER                             = 7865,  -- You can only undertake one supply mission per day. Come back later.
        I_AM_SORRY_WE_SEEM_TO_HAVE_A                                              = 7866,  -- I am sorry. We seem to have a problem. Let me cancel it.
        YOU_DO_NOT_NEED_TO_DONATE_ANY_MORE                                        = 7867,  -- You do not need to donate any more crystals at your current rank. Speak to the guard at the gatehouse for further instructions.
        YOUR_RANK_POINTS_ARE_FULL_WE_VE_ADDED                                     = 7868,  -- Your rank points are full. We've added the excess to your conquest points. You do not need to donate any more crystals. Go to the gatehouse for further instructions.
        GOOD_WORK_CITIZEN_WE_VE_AWARDED_YOU_RANK                                  = 7869,  -- Good work, citizen. We've awarded you rank points for the crystals you've donated.
        YOU_CURRENTLY_HAVE_CONQUEST_POINTS_WOULD_YOU_LIKE                         = 7870,  -- You currently have # conquest points. Would you like to use them to purchase items?
        WHICH_ITEM_DO_YOU_WISH_TO_PURCHASE_COMMON                                 = 7871,  -- Which item do you wish to purchase? Common items (all ranks). 1000-pt. items (rank 1 required).000-pt. items (rank 2 required). 4000-pt. items (rank 3 required). 8000-pt. items (rank 4 required). 16000-pt. items (rank 5 required).4000-pt. items (rank 6 required).2000-pt. items (rank 7 required). 40000-pt. items (rank 8 required). 48000-pt. items (rank 9 required). 56000-pt. items (rank 10 required). Cancel.
        WHICH_ITEM_DO_YOU_WISH_TO_PURCHASE_COMMON_2                               = 7872,  -- Which item do you wish to purchase? Common items (all ranks).000-pt. items (rank 1 required). 4000-pt. items (rank 2 required). 8000-pt. items (rank 3 required). 16000-pt. items (rank 4 required).4000-pt. items (rank 5 required).2000-pt. items (rank 6 required). 40000-pt. items (rank 7 required). 48000-pt. items (rank 8 required). 56000-pt. items (rank 9 required). . Cancel.
        CURRENTLY_THERE_ARE_NO_ITEMS_AVAILABLE_FOR_THAT                           = 7873,  -- Currently there are no items available for that rank.
        DUE_TO_ITS_SPECIAL_NATURE_YOU_CAN_ONLY                                    = 7874,  -- Due to its special nature, you can only purchase or recharge % once until the conquest results tally is performed. Also, you cannot purchase this item if a similar item is already in your possession.
        IT_IS_POSSIBLE_TO_FULLY_RECHARGE_BY_TRADING                               = 7875,  -- It is possible to fully recharge % by trading it to one of your nation's guards, including outpost guards. One charge requires 50 conquest points.
        IT_IS_POSSIBLE_TO_FULLY_RECHARGE_BY_TRADING_2                             = 7876,  -- It is possible to fully recharge % by trading it to one of your nation's guards, including outpost guards. One charge requires 100 conquest points.
        IT_IS_POSSIBLE_TO_FULLY_RECHARGE_BY_TRADING_3                             = 7877,  -- It is possible to fully recharge % by trading it to one of your nation's guards, including outpost guards. One charge requires 200 conquest points.
        DURING_THE_TIME_OF_THE_GREAT_WAR_IT                                       = 7878,  -- During the time of the Great War, it was possible to have this item recharged in exchange for Allied Notes. From my understanding, that practice has recently become commonplace in the Near East. Though you'll be needing Imperial Standing credits if you wish to use the service there.
        YOU_DO_NOT_POSSESS_THE_REQUIRED_TO_FULLY                                  = 7879,  -- You do not possess the # [conquest point/conquest points] required to fully recharge the %.
        PLEASE_BE_AWARE_THAT_YOU_CAN_ONLY_PURCHASE                                = 7880,  -- Please be aware that you can only purchase or recharge % once during the period between each conquest results tally.
        THE_IS_ALREADY_FULLY_CHARGED                                              = 7881,  -- The % is already fully charged.
        YOUR_HAS_RECEIVED_IN_EXCHANGE_FOR_IT_IS                                   = 7882,  -- Your % has received # [charge/charges] in exchange for # [conquest point/conquest points]. It is now fully recharged.
        I_WILL_TRADE_YOU_FOR_YOUR_MAY_IT                                          = 7883,  -- I will trade you % for your %. May it serve you well.
        YOU_DO_NOT_MEET_THE_REQUIREMENTS_TO_PURCHASE                              = 7884,  -- You do not meet the requirements to purchase the %.
        YOUR_RANK_IS_TOO_LOW_TO_PURCHASE_THE                                      = 7885,  -- Your rank is too low to purchase the %.
        YOU_DO_NOT_HAVE_ENOUGH_CONQUEST_POINTS_TO                                 = 7886,  -- You do not have enough conquest points to purchase the %.
        YOU_CANNOT_EQUIP_THE_DO_YOU_STILL_WISH                                    = 7887,  -- You cannot equip the %. Do you still wish to proceed?
        YOUR_LEVEL_IS_TOO_LOW_TO_EQUIP_THE                                        = 7888,  -- Your level is too low to equip the %. Do you still wish to proceed?
        YOU_SEEM_TO_BE_ABLE_TO_EQUIP_THE                                          = 7889,  -- You seem to be able to equip the %. Do you wish to proceed?
        ARE_YOU_SURE_YOU_WANT_TO_PURCHASE_THE                                     = 7890,  -- Are you sure you want to purchase the %?
        PROCEED_YES_PURCHASE_ITEM_CANCEL_PURCHASE                                 = 7891,  -- Proceed? Yes, purchase item. Cancel purchase.
        PROCEED_YES_EVEN_THOUGH_I_CAN_T_EQUIP                                     = 7892,  -- Proceed? Yes, even though I can't equip it. Cancel purchase.
        WHICH_ITEM_DO_YOU_WISH_TO_PURCHASE_NEXT                                   = 7893,  -- Which item do you wish to purchase? %. %. %. %. %. %. %. %. Next page. Previous page. Back.
        WHICH_ITEM_DO_YOU_WISH_TO_PURCHASE_PTS                                    = 7894,  -- Which item do you wish to purchase? %...# pts. %...# pts. %...# pts. %...# pts. %...# pts. %...# pts. %...# pts. %...# pts. Next page. Previous page. Back.
        ENDPARAF                                                                  = 7895,  -- ENDPARAF#
        WHICH_SERVICE_DO_YOU_REQUEST_BUY_SELL_ITEMS                               = 7896,  -- Which service do you request? Buy/Sell items. Teleportation. Nothing.
        DO_YOU_REALLY_WISH_TO_BE_TELEPORTED_YES                                   = 7897,  -- Do you really wish to be teleported? Yes. Teleport with gil. Teleport with conquest points. No.
        WELCOME_TO_THE_BORDER_SHOP_IF_YOU_TRADE                                   = 7898,  -- Welcome to the border shop! If you trade me unused equipment, I'll add their value to your country's region points!
        IT_SHOULD_PLEASE_YOU_TO_KNOW_THAT_I                                       = 7899,  -- It should please you to know that I now also deal in %. Bigger pieces will earn you more points for your nation, and I'll even toss some gil into the equation!
        I_SEE_THAT_YOUR_HOME_COUNTRY_HAS_CONTROL                                  = 7900,  -- I see that your home country has control of this region. Feel free to browse through my wares.
        I_SEE_THAT_YOUR_HOME_COUNTRY_IS_ALLIES                                    = 7901,  -- I see that your home country is allies with the country in control of this region. Feel free to browse through my wares.
        I_CAN_TELEPORT_YOU_TO_YOUR_HOME_COUNTRY                                   = 7902,  -- I can teleport you to your home country for # gil or # conquest [point/points].
        WORD_HAS_IT_THAT_THE_ENTIRE_SET_OF                                        = 7903,  -- Word has it that the entire set of mog tablets has been recovered. Oh, happy day! In honor of the occasion, I can teleport you to your home country free of charge.
        I_AM_TERRIBLY_SORRY_BUT_IT_SEEMS_AS                                       = 7904,  -- I am terribly sorry, but it seems as if you do not have enough gil.
        I_AM_TERRIBLY_SORRY_BUT_IT_SEEMS_AS_2                                     = 7905,  -- I am terribly sorry, but it seems as if you do not have enough conquest points.
        HOWEVER_DUE_TO_YOUR_HOME_COUNTRY_S_LACK                                   = 7906,  -- However, due to your home country's lack of influence in the region, this is the only transaction I am authorized to perform with you at the moment.
        I_AM_LOOKING_FORWARD_TO_DOING_BUSINESS_WITH                               = 7907,  -- I am looking forward to doing business with you again in the future!
        THANK_YOU_THIS_WILL_INCREASE_YOUR_NATION_S                                = 7908,  -- Thank you. This will increase your nation's region points by a small amount. If you have anything else, by all means, trade them to me.
        THANK_YOU_THIS_WILL_INCREASE_YOUR_NATION_S_2                              = 7909,  -- Thank you. This will increase your nation's region points moderately. If you have anything else, by all means, trade them to me.
        THANK_YOU_THIS_WILL_INCREASE_YOUR_NATION_S_3                              = 7910,  -- Thank you. This will increase your nation's region points greatly. If you have anything else, by all means, trade them to me.
        I_COULD_NOT_ACCEPT_ONE_OR_MORE_ITEMS                                      = 7911,  -- I could not accept one or more items you tried to trade me. Please remove those items and try again.
        SORRY_I_CAN_ONLY_TAKE_CERTAIN_TYPES_OF                                    = 7912,  -- Sorry. I can only take certain types of weapons, shields, or armor.
        THANK_YOU_THIS_WILL_INCREASE_YOUR_NATION_S_4                              = 7913,  -- Thank you. This will increase your nation's region points [by a small amount/moderately/greatly]. For this transaction I will also furnish you with # gil.
        MY_APOLOGIES_BUT_THIS_TYPE_OF_ITEM_NEEDS                                  = 7914,  -- My apologies, but this type of item needs to be individually appraised. Please trade them to me one at a time.
        DEBUG_BACK_TO_HOMETOWN                                                    = 7915,  -- (DEBUG) Back to hometown!
        WHAT_DO_YOU_WANT_WOULD_YOU_CAST_SIGNET                                    = 7916,  -- What do you want? Would you cast Signet on me? I'd like to set my home point here. Nothing.
        WHAT_DO_YOU_WANT_PAY_GIL_AND_SET                                          = 7917,  -- What do you want? Pay # gil and set my home point here. Nothing.
        YOUR_HOME_POINT_HAS_BEEN_SET                                              = 7918,  -- Your home point has been set.
        YOU_DO_NOT_HAVE_ENOUGH_GIL_TO_SET                                         = 7919,  -- You do not have enough gil to set your home point here.
        I_WILL_SET_YOUR_HOME_POINT_HERE                                           = 7920,  -- I will set your home point here.
        WE_ARE_CURRENTLY_ON_A_BEASTMAN_PURGING_CAMPAIGN                           = 7921,  -- We are currently on a beastman-purging campaign. We support adventurers from all nations. Do your best to rid the world of those vile creatures.
        WE_ARE_CURRENTLY_CONDUCTING_AN_INTERNATIONAL_EXCHANGE_CAMPAIGN            = 7922,  -- We are currently conducting an international exchange campaign. You may spend your conquest points to purchase items from foreign guards.
        THANKS_TO_YOU_OUR_NATION_IS_NOW_FIRST                                     = 7923,  -- Thanks to you, our nation is now first in the conquest race! Here is a small token of our appreciation.
        ADVENTURERS_FROM_NATIONS_THAT_ARE_RANKED_HIGHER_THAN                      = 7924,  -- Adventurers from nations that are ranked higher than ours in the conquest race may purchase items from us, but at a higher rate.
        YOU_CANNOT_CURRENTLY_PURCHASE_THIS_ITEM_PLEASE_CHOOSE                     = 7925,  -- You cannot currently purchase this item. Please choose another.
        CURRENTLY_OUR_NATION_IS_DISPATCHING_EXPEDITIONARY_FORCES_ACROSS           = 7926,  -- Currently our nation is dispatching Expeditionary Forces across Vana'diel, and requests the participation of brave adventurers such as yourself.
        REQUIREMENTS_FOR_PARTICIPATING_IN_AN_E_F_ARE                              = 7927,  -- Requirements for participating in an E.F. are simple. Your party must consist of # members. Each member must be from this country, rank 3 or higher, and have reached a sufficient level.
        ONCE_YOUR_PARTY_IS_READY_COME_TO_ME                                       = 7928,  -- Once your party is ready, come to me and I will teleport you to the nearest outpost.
        THERE_YOU_WILL_RECEIVE_AN_INSIGNIA_OF_THE                                 = 7929,  -- There, you will receive an insignia of the Expeditionary Force. When you succeed in taking control of the area, you can exchange the insignia for your reward.
        JOIN_THE_E_F_IN_JOIN_THE_E                                                = 7930,  -- Join the E.F. in [Ronfaure/Zulkheim/Norvallen/Gustaberg/Derfland/Sarutabaruta/Kolshushu/Aragoneu/Fauregandi/Valdeaunia/Qufim/Li'Telor/Kuzotz/Vollbow/The Elshimo Lowlands/The Elshimo Uplands]? Join the E.F. Not this time.
        YOUR_PARTY_DOESN_T_HAVE_ENOUGH_MEMBERS_OR                                 = 7931,  -- Your party doesn't have enough members, or some of the members are not in this area. Gather all those who are participating and return here.
        ONE_OF_YOUR_PARTY_MEMBERS_IS_NOT_A                                        = 7932,  -- One of your party members is not a citizen of this country. We do not allow any foreign participants in the E.F.
        ONE_OF_YOUR_PARTY_MEMBERS_HAS_NOT_ACHIEVED                                = 7933,  -- One of your party members has not achieved rank level 3. We cannot reveal any of our tactical strategies to those who have not shown their loyalty to our country.
        ONE_OF_YOUR_PARTY_MEMBERS_IS_BELOW_LEVEL                                  = 7934,  -- One of your party members is below level #. For the safety of the adventurer and those accompanying him or her, we cannot allow anyone below the limit to participate in the E.F.
        I_SEE_THAT_YOU_ARE_READY_I_GRANT                                          = 7935,  -- I see that you are ready. I grant you permission to join the current Expeditionary Force. When you are ready to teleport to the outpost, talk to me once more.
        ARE_YOU_READY_TO_BE_TELEPORTED_TO_REMEMBER                                = 7936,  -- Are you ready to be teleported to [Ronfaure/Zulkheim/Norvallen/Gustaberg/Derfland/Sarutabaruta/Kolshushu/Aragoneu/Fauregandi/Valdeaunia/Qufim/Li'Telor/Kuzotz/Vollbow/The Elshimo Lowlands/The Elshimo Uplands]? Remember that party members who have not been granted permission to attend the E.F. will be left behind.
        TELEPORT_TO_READY_WAIT_JUST_A_MINUTE                                      = 7937,  -- Teleport to [Ronfaure/Zulkheim/Norvallen/Gustaberg/Derfland/Sarutabaruta/Kolshushu/Aragoneu/Fauregandi/Valdeaunia/Qufim/Li'Telor/Kuzotz/Vollbow/The Elshimo Lowlands/The Elshimo Uplands]? Ready! Wait just a minute...
        CANCEL_YOUR_PARTICIPATION_IN_THE_E_F_TO                                   = 7938,  -- Cancel your participation in the E.F. to [Ronfaure/Zulkheim/Norvallen/Gustaberg/Derfland/Sarutabaruta/Kolshushu/Aragoneu/Fauregandi/Valdeaunia/Qufim/Li'Telor/Kuzotz/Vollbow/The Elshimo Lowlands/The Elshimo Uplands]?
        QUIT_THE_E_F_YES_CHANGE_LOCATIONS_NO                                      = 7939,  -- Quit the E.F.? Yes. Change locations. No.
        ARE_YOU_SURE                                                              = 7940,  -- Are you sure?
        REALLY_QUIT_THE_E_F_YES_NO                                                = 7941,  -- Really quit the E.F.? Yes. No.
        I_SEE_IF_YOU_EVER_WISH_TO_PARTICIPATE                                     = 7942,  -- I see. If you ever wish to participate in the future, I will be waiting here to take your application.
        YOUR_EF_BADGE_VANISHES                                                    = 7943,  -- Your EF Badge vanishes!
        KATSU_YAKU_POINTOS                                                        = 7944,  -- Katsu-yaku pointos : #!
        THIS_IS_NO_LONGER_VALID_WE_WILL_DISPOSE                                   = 7945,  -- This % is no longer valid. We will dispose of it here.
        YOUR_INVALID_ENSIGNIAS_HAVE_BEEN_DISPOSED_OF                              = 7946,  -- Your invalid ensignias have been disposed of.
        WELCOME_BACK_FROM_THE_EXPEDITION_OUR_NATION_WAS                           = 7947,  -- Welcome back from the expedition. Our nation was successful in its campaign. Let me give you your reward.
        YOU_RECEIVED_CONQUEST_POINTS                                              = 7948,  -- You received # conquest points!
        WHEN_PARTICIPATING_IN_AN_EXPEDITIONARY_FORCE_CONCENTRATE_YOUR             = 7949,  -- When participating in an Expeditionary Force, concentrate your efforts on fighting foes that give you the most experience points. And don't forget to confiscate the contents of any beastman treasure chest you happen to come upon.
        I_WILL_NOW_HAND_YOU_YOUR_INSIGNIA_BE                                      = 7950,  -- I will now hand you your insignia. Be sure to read the inscription on the back before you begin your duties. Once Signet has been bestowed upon you, prepare to be teleported.
        YOU_COULD_NOT_BE_TELEPORTED_ASK_ME_AGAIN                                  = 7951,  -- You could not be teleported. Ask me again, please.
        THE_CONQUEST_RESULTS_ARE_CURRENTLY_BEING_TALLIED_COME                     = 7952,  -- The conquest results are currently being tallied. Come back later.
        YOU_HAVE_RECEIVED_PERMISSION_TO_JOIN_THE_EXPEDITIONARY                    = 7953,  -- You have received permission to join the Expeditionary Forces!
        CURRENTLY_WE_RANK_FIRST_IN_VANA_DIEL_S                                    = 7954,  -- Currently we rank first in Vana'diel's conquest, but that must not be taken for granted. We must continue our fight to remain on top.
        WE_HAD_FIRST_PLACE_IN_OUR_HANDS_BUT                                       = 7955,  -- We had first place in our hands, but we let it slip away. If we want to be ranked first in Vana'diel, each and every one of us must do their part. I look forward to hearing of your achievements.
        OUR_COUNTRY_HAS_FALLEN_TO_THIRD_IN_THE                                    = 7956,  -- Our country has fallen to third in the conquest of Vana'diel. We must step up our efforts to improve the situation.
        YOU_MUST_FIGHT_IN_BATTLES_THAT_GAIN_HIGH                                  = 7957,  -- You must fight in battles that gain high levels of experience. This is the only way we can bring areas under our country's control.
        CURRENTLY_OUR_COUNTRY_IS_THE_DOMINANT_FORCE_IN                            = 7958,  -- Currently, our country is the dominant force in this region. If we can maintain this level, control of this area will be ours.
        CURRENTLY_OUR_COUNTRY_IS_A_MAJOR_FORCE_IN                                 = 7959,  -- Currently, our country is a major force in this region. However, we cannot take this for granted. If we let down our guard, we will surely lose control of the area!
