        NOBODY_NOT_EVEN_DAVY_JONES_HAS_THE_RIGHT                                  = 9512,  -- Nobody, not even Davy Jones, has the right t' drop his anchor in me harbor without me express permission.
        ARRRG_YE_LOOKS_LIKE_A_TRUSTWORTHY_SOUL_COULD                              = 9513,  -- Arrrg, ye looks like a trustworthy soul. Could ye find it in yer heart t' help out a fellow pirate in need?
        I_VE_GOT_A_BAD_FEELIN_BOUT_THAT                                           = 9514,  -- I've got a bad feelin' 'bout that tree, an' I want t' be 'round if anythin' goes awry.
