        OH_AND_FOR_OUR_MORE_SEASONED_VETERANS_WHO                                 = 11278,  -- Oh, and for our more seasoned veterans who feel there are no challenges left for them here at the track, the CRA has finished preparing a new race. And rumor has that it's a doozie!
        FIRST_OF_ALL_YOUR_CHOCOBO_MUST_BE_FULLY                                   = 11279,  -- First of all, your chocobo must be fully grown. It doesn't matter if you are still tending to it, or if it has been sent to pasture, as long as it is large enough to ride.
        NEXT_YOU_MUST_BRING_ME_EITHER_OR_THIS                                     = 11280,  -- Next, you must bring me either % or %. This is all I will require. There are no hidden fees.
        AS_YOUR_CHOCOBO_DEVELOPS_BE_SURE_TO_RE                                    = 11281,  -- As your chocobo develops, be sure to re-register it. This will ensure that your steed is provided with the equipment that most suits its current condition.
        FINALLY_YOU_MAY_ONLY_REGISTER_ONE_CHOCOBO_AT                              = 11282,  -- Finally, you may only register one chocobo at a time, but are free to register a new bird whenever you wish. You need only speak with me to make any necessary changes.
        ONCE_YOU_HAVE_REGISTERED_YOUR_CHOCOBO_AND_ENTERED                         = 11283,  -- Once you have registered your chocobo and entered it in a competition, the CRA will proceed in assigning it a licensed jockey.
        BEFORE_EACH_RACE_YOU_WILL_BE_GIVEN_THE                                    = 11284,  -- Before each race you will be given the opportunity to give the jockey specific orders on his or her riding style.
        IN_ADDITION_TO_THESE_ORDERS_YOU_CAN_ALSO                                  = 11285,  -- In addition to these orders, you can also provide the jockey with items to use while riding, as well as equipment to improve your chocobo's performance.
        BEFORE_A_RACE_YOU_CAN_ALSO_CHECK_THE                                      = 11286,  -- Before a race, you can also check the strengths and weaknesses of the other participating chocobos. It is recommended that you use this data when deciding on what orders to give, or which items to equip.
        DEPENDING_ON_YOUR_CHOCOBO_S_PERFORMANCE_IN_SELECT                         = 11287,  -- Depending on your chocobo's performance in select CRA-sanctioned races, you may or may not receive a prize consisting of VCS-mint chocobucks.
        CHOCOBUCKS_CAN_BE_USED_TO_PURCHASE_ITEMS_AS                               = 11288,  -- Chocobucks can be used to purchase items, as well as upgrade your mount. Chocobucks are also required to participate in official races.
        CURRENTLY_PLAYERS_CAN_EARN_UP_TO_BUT_NO                                   = 11289,  -- Currently, players can earn up to, but no more than, 1000 chocobucks. However, this may change without notice.
        THERE_ARE_TWO_MAIN_TYPES_OF_RACES                                         = 11290,  -- There are two main types of races.
        THE_FIRST_TYPE_IS_CALLED_AN_OFFICIAL_RACE                                 = 11291,  -- The first type is called an official race. To participate in one of these, you will require chocobucks.
        PLACING_IN_AN_OFFICIAL_RACE_WILL_EARN_YOU                                 = 11292,  -- Placing in an official race will earn you gil. The more races you complete, the more respected you will become in the breeder community.
        YOU_MAY_ALSO_TAKE_PART_IN_AN_OFFICIAL                                     = 11293,  -- You may also take part in an official race as often as needed to complete the specified objectives.
        HOWEVER_AFTER_SOME_OF_THE_MORE_GRUELING_RACES                             = 11294,  -- However, after some of the more grueling races, you may be required to wait before entering the next. This is to give your chocobo, as well as the others, an opportunity to rest before running again.
        THE_SECOND_TYPE_OF_RACE_IS_CALLED_A                                       = 11295,  -- The second type of race is called a free run. Unlike the official races, these can be run at any time, regardless of the results of a previous match.
        YOU_MUST_PAY_A_FEE_IN_GIL_TO                                              = 11296,  -- You must pay a fee in gil to participate in free runs, but you will have the opportunity to earn chocobucks depending on your chocobo's performance. You can join as many free runs as you wish in a single day (Earth time), but extra fees may be required for each additional race. (Stable hands have to make a living, too!)
        THE_CRA_IS_SPLIT_UP_INTO_THREE_RACING                                     = 11297,  -- The CRA is split up into three racing teams representing Bastok, Windurst, and San d'Oria.
        EACH_TEAM_HAS_ITS_OWN_SKILLED_JOCKEYS_AND                                 = 11298,  -- Each team has its own skilled jockeys, and offers unique services that cannot be obtained at the other two.
        BREEDERS_ARE_ALLOWED_TO_REGISTER_WITH_ANY_TEAM                            = 11299,  -- Breeders are allowed to register with any team they like, and may change their affiliation at any time.
        IN_THE_EVENT_THAT_YOU_WISH_TO_LEAVE                                       = 11300,  -- In the event that you wish to leave a racing team, all official race results, as well as earned chocobucks, will be saved.
        YOU_NEVER_HAVE_TO_WORRY_THAT_YOUR_PAST                                    = 11301,  -- You never have to worry that your past accomplishments may be deleted and lost forever. You only need rejoin the team to restore all your old data.
        ANYWAY_THERE_IS_NO_HARM_IN_VISITING_ALL                                   = 11302,  -- Anyway, there is no harm in visiting all three racing teams to find which one suits you best (though I know you'll choose this one).
        AH_IT_SAYS_HERE_THAT_YOU_ARE_A                                            = 11303,  -- Ah, it says here that you are a member of the [San d'Oria/Bastok/Windurst] racing team.
        HAVE_YOU_COME_TODAY_TO_CHANGE_YOUR_AFFILIATION                            = 11304,  -- Have you come today to change your affiliation?
        REMEMBER_YOU_WILL_NOT_BE_ABLE_TO_USE                                      = 11305,  -- Remember, you will not be able to use any chocobucks earned in [San d'Oria/Bastok/Windurst] here, and you will also lose any Solo Victory Points that you may have. Are you sure you want to go through with this?
        JOIN_THIS_TEAM_YES_NO                                                     = 11306,  -- Join this team? Yes. No.
