        WELCOME_LADIES_AND_GENTLEMEN_IT_S_TIME_FOR                                = 11812,  -- Welcome, ladies and gentlemen! It's time for another action-packed chocobo race! I'll be your commentator, Goccilo.
        OUR_SPECIAL_GUESTS_TODAY_ARE_EVERYBODY_S_FAVORITE                         = 11813,  -- Our special guests today are everybody's favorite disgruntled chick, Sakura...
        AND_HER_FAITHFUL_SERVANT_TRANSLATOR_MARKOVICH                             = 11814,  -- ...and her faithful servant/translator, Markovich.
        GOOD_DAY_FOL                                                              = 11815,  -- Good day, fol--
        S_I                                                                       = 11816,  -- s%I
        SAKURA_SAYS_THAT_SHE_LOVES_YOU_ALL_FROM                                   = 11817,  -- Sakura says that she loves you all from the bottom of her tiny heart.
        ALRIGHTY_THEN_OUR_NEXT_RACE_FEATURES_OF_VANA                              = 11818,  -- Alrighty then, our next race features # of Vana'diel's top chocobos. Let us start off by introducing the birds and their jockeys.
        FIRST_WE_HAVE_WHO_WILL_BE_RIDDEN_BY                                       = 11819,  -- First we have %, who will be ridden by [the ace of the chase, Ignazio/three-time chocobo racing alltar, Eudocia/the bloody emperor, Roinolier/the empress of speed, Maurette/Lami-Baami Suave Esquire III/the red rose of racing, Sosopapa/CRA legend, Khowa Mathgalhi/rising CRA star, Bayansh].
        S_S_I                                                                     = 11820,  -- s%s%I
        SHE_SAYS_WHEN_THE_ACE_MAKES_CHASE_THERE                                   = 11821,  -- She says, When the ace makes chase, there's not a bird in Vana'diel who can keep pace.
        SHE_SAYS_AND_YOU_CAN_BET_THE_CHOCOBO                                      = 11822,  -- She says, And you can bet the chocobo farm that this year it'll be 'four-time' alltar!
        SHE_SAYS_THIS_JOCKEY_DOESN_T_GET_HIS                                      = 11823,  -- She says, This jockey doesn't get his name because he yields to through traffic, if you know what I mean.
        SHE_SAYS_THERE_ISN_T_A_JOCKEY_IN                                          = 11824,  -- She says, There isn't a jockey in Vana'diel who loves her steed more than the empress of speed.
        SHE_SAYS_THIS_HEART_THROB_TREATS_HIS_MOUNTS                               = 11825,  -- She says, This heart-throb treats his mounts like he treats his women--with an unparalleled sense of grace, a sixth sense, you could say.
        SHE_SAYS_SOSOPAPA_HAS_GOT_THE_MOVES_TO                                    = 11826,  -- She says, Sosopapa has got the moves to make even the stiffest of necks turn.
        SHE_SAYS_THIS_FORMER_RACING_CHAMPION_HAS_DECIDED                          = 11827,  -- She says, This former racing champion has decided to temporarily come out of retirement (again) for what will be her final race.
        SHE_SAYS_THIS_NATURAL_WASN_T_A_BORN                                       = 11828,  -- She says, This natural wasn't a born natural, but was born with natural ability that naturally transformed him into what we often call a 'natural.'
        NEXT_WE_HAVE_BEING_RIDDEN_BY                                              = 11829,  -- Next we have [Pure Beauty/Ambitious Impact/Young Typhoon], being ridden by [the chocogirl next door, Hazina/dark chocostalker, Pikanza/self-proclaimed chocogeek, Qunbubu].
        SAKURA_SAYS_DON_T_BE_FOOLED_BY_THE                                        = 11830,  -- Sakura says, Don't be fooled by the innocent smile--this girl will rip your chocobo's gizzard out and eat it for a late breakfast or early lunch!
        SAKURA_SAYS_THIS_GALKA_S_UNRELENTING_LOVE_FOR                             = 11831,  -- Sakura says, This Galka's unrelenting love for all things chocobo makes him a dangerous opponent on the track.
        SAKURA_SAYS_THOUSANDS_OF_HOURS_OF_CHOCORESEARCH_HAVE                      = 11832,  -- Sakura says, Thousands of hours of chocoresearch have sharpened the mind of this jolly jockey into a pointy stick, ready to poke and prod anyone who dares stand in her way.
        OUR_NEXT_CHOCOBO_IS_RIDDEN_BY                                             = 11833,  -- Our next chocobo is [Shining Lady/Moon Night/Jet Fire], ridden by [Chanaille, a.k.a. Dances With Chocobos/the chocowhisperer, Sah Zhaowam/Sakura's number one fan, Chamu-Pashamu].
        SAKURA_SAYS_AIN_T_NO_ONE_KNOWS_A                                          = 11834,  -- Sakura says, Ain't no one knows a chocobo's heart like this here lil' lady.
        SAKURA_SAYS_SHE_HAS_A_GOOD_GRASP_OF                                       = 11835,  -- Sakura says, She has a good grasp of our vocabulary, but her pronunciation, especially her gutturals and fricatives, need a little work.
        S_T                                                                       = 11836,  -- s%`t
        SAKURA_SAYS_SHE_KNOWS_WHO_SHE_LL_BE                                       = 11837,  -- Sakura says she knows who she'll be rooting for this race...
