        SHE_SAYS_THAT_SIMPLY_SMELLING_LIKE_A_CHOCOBO                              = 11839,  -- She says that simply smelling like a chocobo doesn't make one a chocobo.
        SHE_SAYS_THAT_BREEDING_CHOCOBOS_IS_LIKE_STOCKING                          = 11840,  -- She says that breeding chocobos is like stocking a warehouse with 10,000 opo-opos and 10,000 typewriters--you are bound to stumble across a masterpiece sooner or later.
