        WELCOME_LADIES_AND_GENTLEMEN_TO_ANOTHER_ROUND_OF                          = 11845,  -- Welcome, ladies and gentlemen to another round of awe-inspiring head-to-head chocobo racing! I am Goccilo, your master of ceremonies.
        AND_JOINING_US_TODAY_ARE_THE_COMMENTATING_DUO                             = 11846,  -- And joining us today are the commentating duo which require no introduction, the equally adroit and adorable Sakura...
