        KEY_ITEMS_BACK_ALL_OPERATION_UNVERIFIED                                   = 14439,  -- Key items Back. All (operation unverified).
        SELCT_KEY_ITEM_BACK_PREVIOUS_PAGE_NEXT_PAGE                               = 14440,  -- Selct key item. Back. Previous page. %. %. %. %. %. %. %. %. %. %. NExt page.
