        PERFECT_THEN_LET_S_GET_RIGHT_DOWN_TO                                      = 15288,  -- Perfect! Then let's get right down to business. The official name of this show is...
        THE_FIRST_ANNUAL_BRYGID_COSPLAY_FIESTA_2                                  = 15289,  -- The First Annual Brygid Cosplay Fiesta!!!
        LET_ME_KNOW_IF_YOU_WANT_TO_HEAR_2                                         = 15290,  -- Let me know if you want to hear more.
        BUT_HERE_S_WHAT_I_WANT_YOU_TO                                             = 15291,  -- But here's what I want you to do in the short term: decide on someone after whom you want to model your costume.
