        THE_ASSIST_CHANNEL_IS_A_SPECIAL_CHAT_CHANNEL                              = 15363,  -- The Assist Channel is a special chat channel that allows adventurers to ask questions and receive advice from veteran players known as mentors.
        PRESS_THE_SPACE_BAR_TO_BRING_UP_THE                                       = 15364,  -- Press the space bar to bring up the text window at the bottom of the screen and type /assistj (your message) or /assiste (your message) to post your message.
